      "lean_file_body": "open Finset\nopen BigOperators\n\nlemma sign_sum_pow_eq_sum_sign_product (n d : ℕ) :\n    ∑ e : Fin d → ℤ, (∑ k : Fin d, e k) ^ n = ∑ x : Fin n → Fin d, ∑ e : Fin d → ℤ, ∏ i : Fin n, e (x i) := by\n  calc\n    ∑ e : Fin d → ℤ, (∑ k : Fin d, e k) ^ n = ∑ e : Fin d → ℤ, ∑ x : Fin n → Fin d, ∏ i : Fin n, e (x i) := by\n      refine Finset.sum_congr rfl fun e _ => ?_\n      rw [Finset.sum_pow' (Finset.univ : Finset (Fin d)) (fun k => e k) n]\n      simp [Finset.sum_pow', Finset.univ, Finset.piFinset]\n    _ = ∑ x : Fin n → Fin d, ∑ e : Fin d → ℤ, ∏ i : Fin n, e (x i) := by\n      rw [Finset.sum_comm]\n",
